 17→// StrategicMemory is a distilled insight derived from synced execution-state
 18→// changes. It persists across sessions and can be used to decide which skills
 19→// should be refreshed.
 20→type StrategicMemory struct {
 21→	ID              int            `json:"id"`
 22→	Category        string         `json:"category"`
 23→	Summary         string         `json:"summary"`
 24→	AffectedSkills  []string       `json:"affected_skills"`
 25→	Evidence        map[string]any `json:"evidence,omitempty"`
 26→	Source          string         `json:"source"`
 27→	SourceKey       string         `json:"source_key"`
 28→	Priority        int            `json:"priority"`
 29→	FirstSeenAt     string         `json:"first_seen_at"`
 30→	LastSeenAt      string         `json:"last_seen_at"`
 31→	OccurrenceCount int            `json:"occurrence_count"`
 32→	CreatedAt       string         `json:"created_at"`
 33→	UpdatedAt       string         `json:"updated_at"`
 34→}
