 36→// StrategicMemoryInput is the write shape for persisting a new distilled
 37→// execution insight.
 38→type StrategicMemoryInput struct {
 39→	Category       string
 40→	Summary        string
 41→	AffectedSkills []string
 42→	Evidence       map[string]any
 43→	Source         string
 44→	SourceKey      string
 45→	Priority       int
 46→}
