 48→// SnapshotCounts summarizes the data volume currently available for skill
 49→// regeneration decisions.
 50→type SnapshotCounts struct {
 51→	EmailCount    int `json:"email_count"`
 52→	LearningCount int `json:"learning_count"`
 53→}
