 55→// StaleSkill describes a tracked skill whose active version is behind the
 56→// latest data, learnings, or strategic memory.
 57→type StaleSkill struct {
 58→	SkillName            string   `json:"skill_name"`
 59→	ActiveVersion        int      `json:"active_version"`
 60→	LastUpdated          string   `json:"last_updated,omitempty"`
 61→	Reasons              []string `json:"reasons"`
 62→	EmailDelta           int      `json:"email_delta,omitempty"`
 63→	LearningDelta        int      `json:"learning_delta,omitempty"`
 64→	StrategicUpdateCount int      `json:"strategic_update_count,omitempty"`
 65→	StrategicCategories  []string `json:"strategic_categories,omitempty"`
 66→}
