316→func listActiveSkillVersions(db *sql.DB) (map[string]activeSkillVersion, error) {
317→	rows, err := db.Query(`
318→		SELECT skill_name, version, email_count, learning_count, created_at
319→		FROM skill_versions
320→		WHERE active = 1
321→	`)
322→	if err != nil {
323→		return nil, fmt.Errorf("listing active skill versions: %w", err)
324→	}
325→	defer rows.Close()
326→
327→	result := make(map[string]activeSkillVersion)
328→	for rows.Next() {
329→		var version activeSkillVersion
330→		if err := rows.Scan(
331→			&version.SkillName,
332→			&version.Version,
333→			&version.EmailCount,
334→			&version.LearningCount,
335→			&version.CreatedAt,
336→		); err != nil {
337→			return nil, fmt.Errorf("scanning active skill version: %w", err)
338→		}
339→		result[version.SkillName] = version
340→	}
341→	return result, rows.Err()
342→}
